import{_ as t,o as a,c as i,a2 as n}from"./chunks/framework.DG4H4-xE.js";const u=JSON.parse('{"title":"Utilizing the Telegram Bot","description":"","frontmatter":{},"headers":[],"relativePath":"en/guide/bot-usage.md","filePath":"en/guide/bot-usage.md"}'),o={name:"en/guide/bot-usage.md"};function r(s,e,l,d,c,h){return a(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="utilizing-the-telegram-bot" tabindex="-1">Utilizing the Telegram Bot <a class="header-anchor" href="#utilizing-the-telegram-bot" aria-label="Permalink to &quot;Utilizing the Telegram Bot&quot;">​</a></h1><p>The vast majority of SREBot interaction takes place straight within your shared or personal Telegram chat interfaces.</p><h2 id="reading-chat-alerts" tabindex="-1">Reading Chat Alerts <a class="header-anchor" href="#reading-chat-alerts" aria-label="Permalink to &quot;Reading Chat Alerts&quot;">​</a></h2><p>Instead of demanding complex routing networks or standalone endpoints, SREBot interfaces directly with your pre-established notifications. When your Alertmanager (or any active bot forwarding Prometheus state changes) outputs a message into the chat beginning with <code>🚨 Alerts Firing:</code>, SREBot naturally:</p><ol><li>Translates the plaintext content line-by-line.</li><li>Identifies semantic <strong>Labels</strong> and <strong>Annotations</strong> embedded inside.</li><li>Parses structural metadata (<code>alertname</code>, <code>cluster</code>, <code>namespace</code>, <code>severity</code>) to log an active <strong>Incident Record</strong> directly within the backend.</li></ol><p>Provided several messages hit the channel sequentially indicating identical failures (sharing the internal <code>fingerprint</code>), SREBot intuitively aggregates those updates to halt parallel duplicate analysis (safeguarding your team from alert fatigue and unnecessary token expenditures).</p><h2 id="result-format-rca-report" tabindex="-1">Result Format (RCA Report) <a class="header-anchor" href="#result-format-rca-report" aria-label="Permalink to &quot;Result Format (RCA Report)&quot;">​</a></h2><p>As soon as the AI effectively processes and correlates data via Prometheus telemetry and Elasticsearch logs, SREBot emits the finalized deduction block. <strong>The bot specifically uses the Reply function</strong> against the original Alertmanager message, keeping conversational context rigidly intact.</p><p><b style="font-size:1.2em;">🔍 Root Cause Analysis</b></p><p><b>Alert:</b> CPUThrottlingHigh <br><b>Cluster:</b> <code>prod-cluster</code> | <b>Namespace:</b> <code>payment-service</code></p><p><b>📊 Findings:</b></p><ul><li>Over the last trailing 15 minutes, sustained CPU utilization hit 99%.</li><li>Searching Elasticsearch exposes rampant <code>OutOfMemory</code> issues and cascading GC failures.</li><li>Connection polling toward the DB timed out routinely at 5-second limits.</li></ul><p><b>🔧 Likely Cause:</b> Insufficient CPU limit allocations restricted the <code>payment-service</code> pod causing intense aggressive throttling. This drove cascading backend degradation and timeout limits against the local DB limits.</p><p><b>💡 Recommended Actions:</b></p><ol><li>Expand the target <code>resources.limits.cpu</code> ceiling inside the corresponding Kubernetes Pod/Deployment definition.</li><li>Cycle the pod immediately to refresh limits.</li></ol><hr><p><em>(Sample SREBot Telegram Reply)</em></p><h2 id="limits-and-constraints" tabindex="-1">Limits and Constraints <a class="header-anchor" href="#limits-and-constraints" aria-label="Permalink to &quot;Limits and Constraints&quot;">​</a></h2><p>Please be aware: If a matched alert notification triggers inside the channel, but your underlying organizational account remains at zero (<code>&lt; 0.0</code>), SREBot forcibly bypasses workflow processing. The bot simply returns a generic fallback note advising personnel about the exhausted balance cap. Review further over at <a href="/en/guide/dashboard">Web Dashboard &amp; Billing</a>.</p>',19)])])}const p=t(o,[["render",r]]);export{u as __pageData,p as default};
